#!/bin/sh
# Name: Fake Registration
# Author: GC777
# Icon: data:image/png;base64,
rm -f /mnt/us/extensions/fakereg/bin/fake.log
touch /mnt/us/extensions/fakereg/bin/fake.log
echo "put reginfo" >> /mnt/us/extensions/fakereg/bin/fake.log
echo "set rw" >> /mnt/us/extensions/fakereg/bin/fake.log
mntroot rw 2>&1 >> /mnt/us/extensions/fakereg/bin/fake.log
echo "set file rights" >> /mnt/us/extensions/fakereg/bin/fake.log
chmod 777 /var/local/java/prefs/reginfo
chattr -i /var/local/java/prefs/reginfo
echo "create reginfo" >> /mnt/us/extensions/fakereg/bin/fake.log
echo "#Mon Jul 29 22:44:35 GMT+02:00 2019" > /var/local/java/prefs/reginfo 
echo "givenName=Myorivate" >> /var/local/java/prefs/reginfo 
echo "userId=amzn1.account.HDGD6DJS6SJDhD4DJD8SPNSGC5SF" >> /var/local/java/prefs/reginfo 
echo "deviceName=My private kindle" >> /var/local/java/prefs/reginfo 
echo "userName=My private kindle" >> /var/local/java/prefs/reginfo 
echo "deviceEmailAddress=myprivatekindle@kindle.com" >> /var/local/java/prefs/reginfo 
echo "" >> /var/local/java/prefs/reginfo 
echo "set file rights" >> /mnt/us/extensions/fakereg/bin/fake.log
chmod 444 /var/local/java/prefs/reginfo
chown root:root /var/local/java/prefs/reginfo
chattr +i /var/local/java/prefs/reginfo
#chown framewor:javauser /var/local/java/prefs/reginfo 2>&1 >> /mnt/us/extensions/fakereg/bin/fake.log
echo "block reg server" >> /mnt/us/extensions/fakereg/bin/fake.log
grep -q "firs-ta-g7g.amazon.com" /etc/hosts || echo "127.0.0.1 firs-ta-g7g.amazon.com" >> /etc/hosts
echo "block delete on deregostration" >> /mnt/us/extensions/fakereg/bin/fake.log
touch /var/local/system/DONT_DELETE_CONTENT_ON_DEREGISTRATION
echo "set r" >> /mnt/us/extensions/fakereg/bin/fake.log
mntroot ro 2>&1 >> /mnt/us/extensions/fakereg/bin/fake.log
echo "reboot" >> /mnt/us/extensions/fakereg/bin/fake.log
reboot